B.R1=new A.b8(["\u6c34\u306b\u306a\u308c\u3001\u53cb\u3088\u3002","Be water, my friend.","\ubb3c\uc774 \ub418\uc5b4\ub77c, \uce5c\uad6c\uc5ec.","Jadilah air, temanku."])
B.Qq=new A.b8(["\u8003\u3048\u308b\u306a\u3001\u611f\u3058\u308d\u3002","Don't think. Feel.","\uc0dd\uac01\ud558\uc9c0 \ub9c8\ub77c, \ub290\uaef4\ub77c.","Jangan berpikir. Rasakan."])
B.QN=new A.b8(["\u6557\u5317\u306f\u5fc3\u306e\u72b6\u614b\u3060\u3002\u8ca0\u3051\u3092\u8a8d\u3081\u306a\u3044\u9650\u308a\u3001\u8ab0\u3082\u672c\u5f53\u306b\u306f\u6557\u308c\u306a\u3044\u3002","Defeat is a state of mind. No one is ever defeated until defeat has been accepted as a reality.","\ud328\ubc30\ub294 \ub9c8\uc74c\uc758 \uc0c1\ud0dc\ub2e4. \ud328\ubc30\ub97c \uc778\uc815\ud558\uc9c0 \uc54a\ub294 \ud55c, \ub204\uad6c\ub3c4 \uc9c4\uc815\uc73c\ub85c \ud328\ubc30\ud558\uc9c0 \uc54a\ub294\ub2e4.","Kekalahan adalah keadaan pikiran. Tak seorang pun benar-benar kalah selama kekalahan belum diterima sebagai kenyataan."])
B.QU=new A.b8(["\u77e5\u308b\u3060\u3051\u3067\u306f\u8db3\u308a\u306a\u3044\u3001\u5b9f\u8df5\u305b\u3088\u3002\u610f\u5fd7\u3060\u3051\u3067\u306f\u8db3\u308a\u306a\u3044\u3001\u884c\u52d5\u305b\u3088\u3002","Knowing is not enough, we must apply. Willing is not enough, we must do.","\uc544\ub294 \uac83\ub9cc\uc73c\ub85c\ub294 \ubd80\uc871\ud558\ub2e4, \uc2e4\ucc9c\ud558\ub77c. \uc758\uc9c0\ub9cc\uc73c\ub85c\ub294 \ubd80\uc871\ud558\ub2e4, \ud589\ub3d9\ud558\ub77c.","Tahu saja tidak cukup, kita harus menerapkan. Niat saja tidak cukup, kita harus bertindak."])
B.Rg=new A.b8(["\u9593\u9055\u3044\u3092\u6050\u308c\u308b\u306a\u3002\u305d\u308c\u306f\u9032\u6b69\u3057\u3066\u3044\u306a\u3044\u8a3c\u62e0\u3060\u3002","Mistakes are always forgivable, if one has the courage to admit them.","\uc2e4\uc218\ub97c \ub450\ub824\uc6cc\ud558\uc9c0 \ub9c8\ub77c. \uc778\uc815\ud560 \uc6a9\uae30\uac00 \uc788\ub2e4\uba74 \uc2e4\uc218\ub294 \uc5b8\uc81c\ub098 \uc6a9\uc11c\ubc1b\uc744 \uc218 \uc788\ub2e4.","Kesalahan selalu bisa dimaafkan, jika seseorang punya keberanian untuk mengakuinya."])
B.R8=new A.b8(["\u76ee\u6a19\u306f\u5e38\u306b\u4e0a\u306b\u3002\u81ea\u5206\u306e\u9650\u754c\u3092\u8d85\u3048\u308d\u3002","A goal is not always meant to be reached, it often serves simply as something to aim at.","\ubaa9\ud45c\ub294 \ud56d\uc0c1 \uc704\ub97c \ud5a5\ud574. \uc790\uc2e0\uc758 \ud55c\uacc4\ub97c \ub118\uc5b4\uc11c\ub77c.","Tujuan tidak selalu dimaksudkan untuk dicapai, sering kali hanya berfungsi sebagai sesuatu untuk dibidik."])
B.R3=new A.b8(["\u30b7\u30f3\u30d7\u30eb\u3055\u3053\u305d\u7a76\u6975\u306e\u6d17\u7df4\u3067\u3042\u308b\u3002","Simplicity is the key to brilliance.","\ub2e8\uc21c\ud568\uc774\uc57c\ub9d0\ub85c \uad81\uadf9\uc758 \uc138\ub828\ub428\uc774\ub2e4.","Kesederhanaan adalah kunci kecemerlangan."])
B.QJ=new A.b8(["\u4f7f\u3048\u308b\u3082\u306e\u3092\u5438\u53ce\u3057\u3001\u4f7f\u3048\u306a\u3044\u3082\u306e\u3092\u6368\u3066\u3001\u81ea\u5206\u3060\u3051\u306e\u3082\u306e\u3092\u52a0\u3048\u3088\u3002","Absorb what is useful, discard what is useless and add what is specifically your own.","\uc4f8\ubaa8 \uc788\ub294 \uac83\uc744 \ud761\uc218\ud558\uace0, \uc4f8\ubaa8\uc5c6\ub294 \uac83\uc744 \ubc84\ub9ac\uace0, \uc790\uc2e0\ub9cc\uc758 \uac83\uc744 \ub354\ud558\ub77c.","Serap apa yang berguna, buang apa yang tidak berguna, dan tambahkan apa yang menjadi milikmu sendiri."])
B.QL=new A.b8(["\u9577\u3044\u65c5\u3082\u4e00\u6b69\u304b\u3089\u59cb\u307e\u308b\u3002","A journey of a thousand miles begins with a single step.","\uae34 \uc5ec\uc815\ub3c4 \ud55c \uac78\uc74c\ubd80\ud130 \uc2dc\uc791\ub41c\ub2e4.","Perjalanan seribu mil dimulai dengan satu langkah."])
B.Qu=new A.b8(["\u578b\u3092\u5b66\u3073\u3001\u578b\u3092\u5b88\u308a\u3001\u578b\u3092\u7834\u308c\u3002","Learn the rules so you know how to break them properly.","\ud2c0\uc744 \ubc30\uc6b0\uace0, \ud2c0\uc744 \uc9c0\ud0a4\uace0, \ud2c0\uc744 \uae68\ub77c.","Pelajari aturannya agar kamu tahu cara melanggarnya dengan benar."])
B.QT=new A.b8(["\u901f\u3055\u3068\u306f\u898b\u3048\u306a\u3044\u3053\u3068\u3067\u306f\u306a\u3044\u3002\u9069\u5207\u306a\u6642\u306b\u52d5\u304f\u3053\u3068\u3060\u3002","Speed is not about seeing \u2014 it is about moving at the right time.","\ube60\ub984\uc774\ub780 \ubcf4\uc774\uc9c0 \uc54a\ub294 \uac83\uc774 \uc544\ub2c8\ub2e4. \uc801\uc808\ud55c \ub54c\uc5d0 \uc6c0\uc9c1\uc774\ub294 \uac83\uc774\ub2e4.","Kecepatan bukan tentang melihat \u2014 ini tentang bergerak di waktu yang tepat."])
B.QI=new A.b8(["\u4e00\u4e07\u901a\u308a\u306e\u8e74\u308a\u3092\u4e00\u5ea6\u305a\u3064\u7df4\u7fd2\u3057\u305f\u8005\u306f\u6016\u304f\u306a\u3044\u3002\u4e00\u3064\u306e\u8e74\u308a\u3092\u4e00\u4e07\u56de\u7df4\u7fd2\u3057\u305f\u8005\u304c\u6016\u3044\u3002","I fear not the man who has practiced 10,000 kicks once, but I fear the man who has practiced one kick 10,000 times.","\ub9cc \uac00\uc9c0 \ubc1c\ucc28\uae30\ub97c \ud55c \ubc88\uc529 \uc5f0\uc2b5\ud55c \uc790\ub294 \ub450\ub835\uc9c0 \uc54a\ub2e4. \ud558\ub098\uc758 \ubc1c\ucc28\uae30\ub97c \ub9cc \ubc88 \uc5f0\uc2b5\ud55c \uc790\uac00 \ub450\ub835\ub2e4.","Aku tidak takut pada orang yang berlatih 10.000 tendangan sekali, tapi aku takut pada orang yang berlatih satu tendangan 10.000 kali."])
B.Qr=new A.b8(["\u81ea\u5206\u3092\u8868\u73fe\u3059\u308b\u52c7\u6c17\u3092\u6301\u3066\u3002","Always be yourself, express yourself, have faith in yourself.","\uc790\uc2e0\uc744 \ud45c\ud604\ud558\ub294 \uc6a9\uae30\ub97c \uac00\uc838\ub77c.","Selalu jadilah dirimu sendiri, ekspresikan dirimu, percayalah pada dirimu."])
B.R_=new A.b8(["\u4eba\u751f\u306e\u5927\u304d\u306a\u904e\u3061\u306f\u3001\u9593\u9055\u3048\u308b\u3053\u3068\u3092\u5e38\u306b\u6050\u308c\u308b\u3053\u3068\u3060\u3002","Life's battles don't always go to the stronger or faster man. But sooner or later, the man who wins is the man who thinks he can.","\uc778\uc0dd\uc758 \ud070 \uc2e4\uc218\ub294 \uc2e4\uc218\ud558\ub294 \uac83\uc744 \ud56d\uc0c1 \ub450\ub824\uc6cc\ud558\ub294 \uac83\uc774\ub2e4.","Pertempuran hidup tidak selalu dimenangkan yang lebih kuat atau cepat. Tapi cepat atau lambat, yang menang adalah yang percaya dia bisa."])
B.QZ=new A.b8(["\u81ea\u5206\u3092\u77e5\u308b\u3053\u3068\u304c\u5168\u3066\u306e\u77e5\u6075\u306e\u59cb\u307e\u308a\u3060\u3002","To know oneself is to study oneself in action with another person.","\uc790\uc2e0\uc744 \uc544\ub294 \uac83\uc774 \ubaa8\ub4e0 \uc9c0\ud61c\uc758 \uc2dc\uc791\uc774\ub2e4.","Mengenal diri sendiri adalah mempelajari diri sendiri dalam tindakan bersama orang lain."])
B.R0=new A.b8(["\u5f62\u306b\u3053\u3060\u308f\u308b\u306a\u3002\u5f62\u306a\u304d\u5f62\u3001\u305d\u308c\u304c\u7a76\u6975\u3060\u3002","Be formless, shapeless, like water.","\ud615\ud0dc\uc5d0 \uc9d1\ucc29\ud558\uc9c0 \ub9c8\ub77c. \ud615\ud0dc \uc5c6\ub294 \ud615\ud0dc, \uadf8\uac83\uc774 \uad81\uadf9\uc774\ub2e4.","Jadilah tanpa bentuk, tanpa rupa, seperti air."])
B.R6=new A.b8(["\u9650\u754c\u306f\u5b58\u5728\u3057\u306a\u3044\u3002\u3042\u308b\u306e\u306f\u505c\u6ede\u3060\u3051\u3060\u3002\u305d\u3053\u306b\u7559\u307e\u308b\u306a\u3002","There are no limits. There are only plateaus, and you must not stay there.","\ud55c\uacc4\ub294 \uc874\uc7ac\ud558\uc9c0 \uc54a\ub294\ub2e4. \uc788\ub294 \uac83\uc740 \uc815\uccb4\ubfd0\uc774\ub2e4. \uac70\uae30\uc5d0 \uba38\ubb3c\uc9c0 \ub9c8\ub77c.","Tidak ada batasan. Yang ada hanya dataran tinggi, dan kamu tidak boleh tinggal di sana."])
B.QV=new A.b8(["\u5fcd\u8010\u306f\u96c6\u4e2d\u529b\u3067\u3042\u308a\u3001\u5f37\u3055\u3067\u3042\u308b\u3002","Patience is not passive; on the contrary, it is concentrated strength.","\uc778\ub0b4\ub294 \uc9d1\uc911\ub825\uc774\uba70 \uac15\ud568\uc774\ub2e4.","Kesabaran bukan pasif; sebaliknya, itu adalah kekuatan yang terpusat."])
B.R4=new A.b8(["\u5e78\u798f\u3068\u306f\u4f55\u304b\u3092\u6210\u3057\u9042\u3052\u305f\u8005\u3060\u3051\u304c\u611f\u3058\u308b\u3082\u306e\u3060\u3002","Ever since I was a child I have had this instinctive urge for expansion and growth.","\ud589\ubcf5\uc774\ub780 \ubb34\uc5b8\uac00\ub97c \uc774\ub8ec \uc790\ub9cc\uc774 \ub290\ub07c\ub294 \uac83\uc774\ub2e4.","Sejak kecil aku memiliki dorongan naluriah untuk berkembang dan bertumbuh."])
B.Re=new A.b8(["\u771f\u306e\u5f37\u3055\u306f\u3001\u81ea\u5206\u81ea\u8eab\u3092\u5236\u5fa1\u3067\u304d\u308b\u8005\u306b\u3042\u308b\u3002","The key to immortality is first living a life worth remembering.","\uc9c4\uc815\ud55c \uac15\ud568\uc740 \uc790\uae30 \uc790\uc2e0\uc744 \uc81c\uc5b4\ud560 \uc218 \uc788\ub294 \uc790\uc5d0\uac8c \uc788\ub2e4.","Kunci keabadian adalah pertama-tama menjalani kehidupan yang layak dikenang."])
B.Ra=new A.b8(["\u6d41\u308c\u306b\u8eab\u3092\u4efb\u305b\u3001\u67d4\u8edf\u306b\u5bfe\u5fdc\u305b\u3088\u3002","You must be shapeless, formless, like water.","\ud750\ub984\uc5d0 \ubab8\uc744 \ub9e1\uae30\uace0 \uc720\uc5f0\ud558\uac8c \ub300\uc751\ud558\ub77c.","Kamu harus tanpa bentuk, tanpa rupa, seperti air."])
B.R5=new A.b8(["\u6210\u529f\u3068\u306f\u65e5\u3005\u306e\u7df4\u7fd2\u306e\u7a4d\u307f\u91cd\u306d\u3060\u3002\u4e00\u65e5\u306b\u3057\u3066\u6210\u308b\u3082\u306e\u3067\u306f\u306a\u3044\u3002","Long-term consistency trumps short-term intensity.","\uc131\uacf5\uc774\ub780 \ub9e4\uc77c\uc758 \uc5f0\uc2b5\uc774 \uc313\uc778 \uac83\uc774\ub2e4. \ud558\ub8e8\uc544\uce68\uc5d0 \uc774\ub8e8\uc5b4\uc9c0\ub294 \uac83\uc774 \uc544\ub2c8\ub2e4.","Konsistensi jangka panjang mengalahkan intensitas jangka pendek."])
B.QD=new A.b8(["\u5049\u5927\u306a\u5e2b\u306f\u6307\u3055\u3059\u304c\u3001\u6307\u3092\u898b\u308b\u306a\u3002\u6708\u3092\u898b\u308d\u3002","It's like a finger pointing away to the moon. Don't concentrate on the finger or you will miss all that heavenly glory.","\uc704\ub300\ud55c \uc2a4\uc2b9\uc740 \uac00\ub9ac\ud0a4\uc9c0\ub9cc, \uc190\uac00\ub77d\uc744 \ubcf4\uc9c0 \ub9c8\ub77c. \ub2ec\uc744 \ubcf4\ub77c.","Seperti jari yang menunjuk ke bulan. Jangan fokus pada jarinya atau kamu akan melewatkan semua kemuliaan langit itu."])
B.QF=new A.b8(["\u8ca0\u3051\u305f\u5f8c\u306b\u3069\u3046\u7acb\u3061\u4e0a\u304c\u308b\u304b\u304c\u3001\u304a\u524d\u3068\u3044\u3046\u4eba\u9593\u3092\u6c7a\u3081\u308b\u3002","The successful warrior is the average man, with laser-like focus.","\uc9c4 \ud6c4\uc5d0 \uc5b4\ub5bb\uac8c \uc77c\uc5b4\uc11c\ub290\ub0d0\uac00 \ub108\ub77c\ub294 \uc0ac\ub78c\uc744 \uacb0\uc815\ud55c\ub2e4.","Pejuang yang sukses adalah orang biasa dengan fokus setajam laser."])
B.Rh=new A.b8(["\u5668\u3092\u7a7a\u306b\u3057\u308d\u3002\u305d\u3046\u3059\u308c\u3070\u65b0\u3057\u3044\u3082\u306e\u3067\u6e80\u305f\u3055\u308c\u308b\u3002","Empty your cup so that it may be filled.","\uadf8\ub987\uc744 \ube44\uc6cc\ub77c. \uadf8\ub7ec\uba74 \uc0c8\ub85c\uc6b4 \uac83\uc73c\ub85c \ucc44\uc6cc\uc9c4\ub2e4.","Kosongkan gelasmu agar bisa diisi."])
B.Rd=new A.b8(["\u8abf\u548c\u3068\u306f\u3001\u5bfe\u7acb\u306e\u4e2d\u306b\u3053\u305d\u898b\u51fa\u3055\u308c\u308b\u3002","In the middle of chaos lies opportunity.","\uc870\ud654\ub780 \ub300\ub9bd \uc18d\uc5d0\uc11c\uc57c\ub9d0\ub85c \ubc1c\uacac\ub41c\ub2e4.","Di tengah kekacauan terdapat peluang."])
B.R2=new A.b8(["\u884c\u52d5\u3053\u305d\u304c\u771f\u5b9f\u3060\u3002\u8a00\u8449\u3067\u306f\u306a\u304f\u3002","If you spend too much time thinking about a thing, you will never get it done.","\ud589\ub3d9\uc774\uc57c\ub9d0\ub85c \uc9c4\uc2e4\uc774\ub2e4. \ub9d0\uc774 \uc544\ub2c8\ub77c.","Jika kamu terlalu lama memikirkan sesuatu, kamu tidak akan pernah menyelesaikannya."])
B.QS=new A.b8(["\u5f37\u304f\u306a\u308b\u305f\u3081\u306b\u6226\u3046\u306e\u3067\u306f\u306a\u3044\u3002\u6226\u3046\u3053\u3068\u3067\u5f37\u304f\u306a\u308b\u306e\u3060\u3002","Do not pray for an easy life, pray for the strength to endure a difficult one.","\uac15\ud574\uc9c0\uae30 \uc704\ud574 \uc2f8\uc6b0\ub294 \uac83\uc774 \uc544\ub2c8\ub2e4. \uc2f8\uc6c0\uc73c\ub85c\uc368 \uac15\ud574\uc9c0\ub294 \uac83\uc774\ub2e4.","Jangan berdoa untuk hidup yang mudah, berdoalah untuk kekuatan menjalani yang sulit."])
B.Qs=new A.b8(["\u5909\u5316\u3053\u305d\u304c\u4e0d\u5909\u306e\u771f\u7406\u3060\u3002","The only way to deal with change is to embrace it.","\ubcc0\ud654\uc57c\ub9d0\ub85c \ubd88\ubcc0\uc758 \uc9c4\ub9ac\ub2e4.","Satu-satunya cara menghadapi perubahan adalah merangkulnya."])
B.Qz=new A.b8(["\u4eca\u65e5\u3068\u3044\u3046\u65e5\u3092\u5168\u529b\u3067\u751f\u304d\u308d\u3002\u305d\u308c\u304c\u6700\u9ad8\u306e\u5fa9\u8b90\u3060\u3002","Real living is living for others.","\uc624\ub298\uc774\ub77c\ub294 \ub0a0\uc744 \uc804\ub825\uc73c\ub85c \uc0b4\uc544\ub77c. \uadf8\uac83\uc774 \ucd5c\uace0\uc758 \ubcf5\uc218\ub2e4.","Hidup yang nyata adalah hidup untuk orang lain."])
B.Qp=new A.b8(["\u601d\u3046\u3088\u3046\u306b\u306a\u308c\u3002","As you think, so shall you become.","\uc0dd\uac01\ud558\ub294 \ub300\ub85c \ub418\uc5b4\ub77c.","Seperti yang kamu pikirkan, begitulah kamu menjadi."])
B.Qy=new A.b8(["\u7af9\u306f\u5d50\u306b\u66f2\u304c\u308b\u304c\u3001\u6298\u308c\u306a\u3044\u3002\u67d4\u8edf\u6027\u3053\u305d\u304c\u5f37\u3055\u3060\u3002","Notice that the stiffest tree is most easily cracked, while the bamboo survives by bending in the wind.","\ub300\ub098\ubb34\ub294 \ud3ed\ud48d\uc5d0 \ud718\uc5b4\uc9c0\uc9c0\ub9cc \ubd80\ub7ec\uc9c0\uc9c0 \uc54a\ub294\ub2e4. \uc720\uc5f0\ud568\uc774\uc57c\ub9d0\ub85c \uac15\ud568\uc774\ub2e4.","Perhatikan bahwa pohon paling kaku paling mudah patah, sementara bambu bertahan dengan menekuk mengikuti angin."])
B.QM=new A.b8(["\u5df1\u306e\u9650\u754c\u3092\u8a2d\u3051\u308b\u306a\u3002\u9650\u754c\u306f\u3042\u306a\u305f\u306e\u4e2d\u306b\u3042\u308b\u58c1\u3060\u3002","If you always put a limit on what you do, it will spread into your work and your life.","\uc2a4\uc2a4\ub85c \ud55c\uacc4\ub97c \uc815\ud558\uc9c0 \ub9c8\ub77c. \ud55c\uacc4\ub294 \ub124 \uc548\uc5d0 \uc788\ub294 \ubcbd\uc774\ub2e4.","Jika kamu selalu membatasi apa yang kamu lakukan, itu akan menyebar ke pekerjaanmu dan hidupmu."])
B.Qn=new A.b8(["\u5e2b\u5320\u306f\u6249\u3092\u958b\u304f\u3002\u901a\u308b\u306e\u306f\u3042\u306a\u305f\u81ea\u8eab\u3060\u3002","A teacher is never a giver of truth \u2014 he is a guide, a pointer to the truth that each student must find.","\uc2a4\uc2b9\uc740 \ubb38\uc744 \uc5f0\ub2e4. \uc9c0\ub098\uac00\ub294 \uac83\uc740 \ub108 \uc790\uc2e0\uc774\ub2e4.","Guru bukanlah pemberi kebenaran \u2014 dia adalah pemandu menuju kebenaran yang harus ditemukan setiap murid sendiri."])
B.QY=new A.b8(["\u771f\u306e\u719f\u9054\u3068\u306f\u81ea\u5206\u81ea\u8eab\u3092\u8d85\u3048\u308b\u3053\u3068\u304b\u3089\u751f\u307e\u308c\u308b\u3002","True mastery transcends any particular art. It stems from mastery of oneself.","\uc9c4\uc815\ud55c \uc219\ub2ec\uc774\ub780 \uc790\uae30 \uc790\uc2e0\uc744 \ub118\uc5b4\uc11c\ub294 \uac83\uc5d0\uc11c \ube44\ub86f\ub41c\ub2e4.","Penguasaan sejati melampaui seni tertentu. Ia berasal dari penguasaan diri sendiri."])
B.QW=new A.b8(["\u624d\u80fd\u306f\u7df4\u7fd2\u306b\u52dd\u3066\u306a\u3044\u3002","There are no shortcuts in the cultivation of kung fu. You must practice hard, diligently, and consistently.","\uc7ac\ub2a5\uc740 \uc5f0\uc2b5\uc744 \uc774\uae38 \uc218 \uc5c6\ub2e4.","Tidak ada jalan pintas dalam memupuk kung fu. Kamu harus berlatih keras, tekun, dan konsisten."])
B.Ql=new A.b8(["\u6050\u308c\u3092\u77e5\u308b\u3053\u3068\u3067\u3001\u6050\u308c\u304b\u3089\u81ea\u7531\u306b\u306a\u308c\u308b\u3002","Fear comes from uncertainty; we can eliminate the fear within us when we know ourselves better.","\ub450\ub824\uc6c0\uc744 \uc544\ub294 \uac83\uc73c\ub85c \ub450\ub824\uc6c0\uc5d0\uc11c \uc790\uc720\ub85c\uc6cc\uc9c8 \uc218 \uc788\ub2e4.","Rasa takut datang dari ketidakpastian; kita bisa menghilangkannya ketika kita lebih mengenal diri sendiri."])
B.Rb=new A.b8(["\u6642\u9593\u3092\u611b\u3059\u308b\u306a\u3089\u3001\u6642\u9593\u3092\u7121\u99c4\u306b\u3059\u308b\u306a\u3002\u6642\u9593\u3053\u305d\u304c\u547d\u3060\u3002","If you love life, don't waste time, for time is what life is made up of.","\uc2dc\uac04\uc744 \uc0ac\ub791\ud55c\ub2e4\uba74 \uc2dc\uac04\uc744 \ub0ad\ube44\ud558\uc9c0 \ub9c8\ub77c. \uc2dc\uac04\uc774\uc57c\ub9d0\ub85c \uc0dd\uba85\uc774\ub2e4.","Jika kamu mencintai hidup, jangan buang waktu, karena waktu adalah bahan pembentuk hidup."])
B.QB=new A.b8(["\u4eba\u751f\u306e\u610f\u5473\u3068\u306f\u3001\u305d\u308c\u3092\u751f\u304d\u5207\u308b\u3053\u3068\u306b\u3042\u308b\u3002","The meaning of life is that it is to be lived.","\uc778\uc0dd\uc758 \uc758\ubbf8\ub780 \uadf8\uac83\uc744 \uc0b4\uc544\ub0b4\ub294 \ub370 \uc788\ub2e4.","Makna hidup adalah bahwa ia harus dijalani."])
B.QQ=new A.b8(["\u65e5\u3005\u5897\u3084\u3059\u306e\u3067\u306f\u306a\u304f\u3001\u65e5\u3005\u524a\u308c\u3002\u4e0d\u8981\u306a\u3082\u306e\u3092\u5207\u308a\u843d\u3068\u305b\u3002","It is not daily increase but daily decrease \u2014 hack away at the unessential.","\ub9e4\uc77c \ub298\ub9ac\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \ub9e4\uc77c \ub35c\uc5b4\ub0b4\ub77c. \ubd88\ud544\uc694\ud55c \uac83\uc744 \uc798\ub77c\ub0b4\ub77c.","Bukan penambahan harian tapi pengurangan harian \u2014 singkirkan yang tidak penting."])
B.QP=new A.b8(["\u5b66\u3076\u3068\u306f\u767a\u898b\u3059\u308b\u3053\u3068\u3060\u3002\u767a\u898b\u3059\u308b\u3053\u3068\u3068\u306f\u3001\u81ea\u7531\u306b\u306a\u308b\u3053\u3068\u3060\u3002","Learning is never cumulative, it is a movement of knowing which has no beginning and no end.","\ubc30\uc6b4\ub2e4\ub294 \uac83\uc740 \ubc1c\uacac\ud558\ub294 \uac83\uc774\ub2e4. \ubc1c\uacac\ud55c\ub2e4\ub294 \uac83\uc740 \uc790\uc720\ub85c\uc6cc\uc9c0\ub294 \uac83\uc774\ub2e4.","Belajar tidak pernah kumulatif, itu adalah gerakan mengetahui yang tidak memiliki awal dan akhir."])
B.Qx=new A.b8(["\u52d5\u4f5c\u306e\u7121\u99c4\u3092\u7701\u3051\u3002\u4e00\u3064\u306e\u52d5\u4f5c\u3067\u52dd\u8ca0\u3092\u6c7a\u3081\u308d\u3002","Economy of motion \u2014 use no more than is necessary.","\ub3d9\uc791\uc758 \ub0ad\ube44\ub97c \uc5c6\uc560\ub77c. \ud558\ub098\uc758 \ub3d9\uc791\uc73c\ub85c \uc2b9\ubd80\ub97c \uacb0\uc815\ud558\ub77c.","Ekonomi gerak \u2014 jangan gunakan lebih dari yang diperlukan."])
B.QE=new A.b8(["\u82b8\u8853\u3068\u306f\u81ea\u5df1\u8868\u73fe\u3060\u3002\u5f62\u5f0f\u3067\u306f\u306a\u3044\u3002","Art calls for complete mastery of techniques, developed by reflection within the soul.","\uc608\uc220\uc774\ub780 \uc790\uae30\ud45c\ud604\uc774\ub2e4. \ud615\uc2dd\uc774 \uc544\ub2c8\ub2e4.","Seni memerlukan penguasaan teknik yang lengkap, yang dikembangkan melalui refleksi dalam jiwa."])
B.Qm=new A.b8(["\u6012\u308a\u306f\u9727\u3060\u3002\u305d\u308c\u306f\u5224\u65ad\u3092\u66c7\u3089\u305b\u308b\u3002","Anger is a wind which blows out the lamp of the mind.","\ubd84\ub178\ub294 \uc548\uac1c\ub2e4. \uadf8\uac83\uc740 \ud310\ub2e8\uc744 \ud750\ub9ac\uac8c \ud55c\ub2e4.","Kemarahan adalah angin yang meniup padamnya pelita pikiran."])
B.QK=new A.b8(["\u5b8c\u5168\u306a\u935b\u932c\u3068\u306f\u5fc3\u3068\u4f53\u306e\u7d71\u4e00\u3060\u3002","The perfect technique is the expression of the mind and the body as one.","\uc644\ubcbd\ud55c \ub2e8\ub828\uc774\ub780 \ub9c8\uc74c\uacfc \ubab8\uc758 \ud1b5\uc77c\uc774\ub2e4.","Teknik sempurna adalah ekspresi pikiran dan tubuh sebagai satu."])
B.QR=new A.b8(["\u9759\u306e\u4e2d\u306b\u52d5\u3042\u308a\u3001\u52d5\u306e\u4e2d\u306b\u9759\u3042\u308a\u3002","In stillness there is movement, in movement there is stillness.","\uc815(\u975c) \uc18d\uc5d0 \ub3d9(\u52d5)\uc774 \uc788\uace0, \ub3d9 \uc18d\uc5d0 \uc815\uc774 \uc788\ub2e4.","Dalam ketenangan ada gerakan, dalam gerakan ada ketenangan."])
B.Qt=new A.b8(["\u610f\u8b58\u306e\u904e\u5270\u3053\u305d\u304c\u3001\u3042\u3089\u3086\u308b\u52d5\u4f5c\u306e\u59a8\u3052\u3068\u306a\u308b\u3002","The consciousness of self is the greatest hindrance to the proper execution of all physical action.","\uacfc\ub3c4\ud55c \uc758\uc2dd\uc774\uc57c\ub9d0\ub85c \ubaa8\ub4e0 \ub3d9\uc791\uc758 \ubc29\ud574\uac00 \ub41c\ub2e4.","Kesadaran diri yang berlebihan adalah hambatan terbesar bagi pelaksanaan semua tindakan fisik."])
B.QA=new A.b8(["\u6b66\u8853\u306f\u5df1\u306e\u6b20\u70b9\u3092\u6620\u3059\u93e1\u3060\u3002","The martial arts are a mirror to reflect your own blemishes.","\ubb34\uc220\uc740 \uc790\uc2e0\uc758 \uacb0\uc810\uc744 \ube44\ucd94\ub294 \uac70\uc6b8\uc774\ub2e4.","Seni bela diri adalah cermin untuk merefleksikan kekuranganmu sendiri."])
B.Qv=new A.b8(["\u6628\u65e5\u3088\u308a\u4eca\u65e5\u3001\u4eca\u65e5\u3088\u308a\u660e\u65e5\u3002\u5e38\u306b\u524d\u9032\u305b\u3088\u3002","Seek the highest form of the art you are studying \u2014 perfect yourself, transcend technique.","\uc5b4\uc81c\ubcf4\ub2e4 \uc624\ub298, \uc624\ub298\ubcf4\ub2e4 \ub0b4\uc77c. \ud56d\uc0c1 \uc804\uc9c4\ud558\ub77c.","Carilah bentuk tertinggi dari seni yang kamu pelajari \u2014 sempurnakan dirimu, lampaui teknik."])
B.Qw=new A.b8(["\u5b64\u72ec\u3092\u6050\u308c\u308b\u306a\u3002\u5b64\u72ec\u306e\u4e2d\u3067\u3053\u305d\u81ea\u5206\u3068\u5411\u304d\u5408\u3048\u308b\u3002","In the silence of solitude, you hear the clearest truth.","\uace0\ub3c5\uc744 \ub450\ub824\uc6cc\ud558\uc9c0 \ub9c8\ub77c. \uace0\ub3c5 \uc18d\uc5d0\uc11c\uc57c\ub9d0\ub85c \uc790\uc2e0\uacfc \ub9c8\uc8fc\ud560 \uc218 \uc788\ub2e4.","Dalam keheningan kesendirian, kamu mendengar kebenaran yang paling jernih."])
B.Rc=new A.b8(["\u771f\u306e\u6b66\u9053\u5bb6\u306f\u5e73\u548c\u3092\u611b\u3059\u308b\u3002","The true martial artist does not fight for aggression \u2014 he cultivates the art of peace.","\uc9c4\uc815\ud55c \ubb34\ub3c4\uac00\ub294 \ud3c9\ud654\ub97c \uc0ac\ub791\ud55c\ub2e4.","Seniman bela diri sejati tidak bertarung untuk agresi \u2014 dia memupuk seni perdamaian."])
B.Rf=new A.b8(["\u4f53\u304c\u75b2\u308c\u305f\u3068\u304d\u3001\u7cbe\u795e\u304c\u524d\u306b\u9032\u307e\u305b\u308b\u3002","When your body says stop, your spirit says continue.","\ubab8\uc774 \uc9c0\ucce4\uc744 \ub54c, \uc815\uc2e0\uc774 \uc55e\uc73c\ub85c \ub098\uc544\uac00\uac8c \ud55c\ub2e4.","Ketika tubuhmu berkata berhenti, jiwamu berkata lanjutkan."])
B.QO=new A.b8(["\u6249\u3092\u53e9\u304d\u7d9a\u3051\u308d\u3002\u30c1\u30e3\u30f3\u30b9\u306f\u7528\u610f\u3055\u308c\u305f\u8005\u306e\u3068\u3053\u308d\u306b\u3084\u3063\u3066\u6765\u308b\u3002","Opportunity does not knock \u2014 it presents itself when you beat down the door.","\ubb38\uc744 \uacc4\uc18d \ub450\ub4dc\ub824\ub77c. \uae30\ud68c\ub294 \uc900\ube44\ub41c \uc790\uc5d0\uac8c \ucc3e\uc544\uc628\ub2e4.","Peluang tidak mengetuk \u2014 ia muncul saat kamu mendobrak pintunya."])
B.QC=new A.b8(["\u6b66\u8853\u306f\u6575\u3092\u5012\u3059\u6280\u3067\u306f\u306a\u304f\u3001\u81ea\u5206\u3092\u8d85\u3048\u308b\u6280\u3060\u3002","Martial art is not about defeating an opponent \u2014 it is about exceeding your own limitations.","\ubb34\uc220\uc740 \uc801\uc744 \uc4f0\ub7ec\ub728\ub9ac\ub294 \uae30\uc220\uc774 \uc544\ub2c8\ub77c \uc790\uc2e0\uc744 \ub118\uc5b4\uc11c\ub294 \uae30\uc220\uc774\ub2e4.","Seni bela diri bukan tentang mengalahkan lawan \u2014 ini tentang melampaui batasanmu sendiri."])
B.R7=new A.b8(["\u5931\u6557\u306f\u7d42\u308f\u308a\u3067\u306f\u306a\u3044\u3002\u305d\u308c\u306f\u65b0\u3057\u3044\u59cb\u307e\u308a\u3060\u3002","Defeat is not a disgrace \u2014 it is only a new beginning.","\uc2e4\ud328\ub294 \ub05d\uc774 \uc544\ub2c8\ub2e4. \uadf8\uac83\uc740 \uc0c8\ub85c\uc6b4 \uc2dc\uc791\uc774\ub2e4.","Kegagalan bukanlah aib \u2014 itu hanyalah awal yang baru."])
B.Qo=new A.b8(["\u9053\u3092\u77e5\u308b\u3053\u3068\u3068\u9053\u3092\u6b69\u304f\u3053\u3068\u306f\u9055\u3046\u3002","Knowing the way and walking the way are two entirely different things.","\uae38\uc744 \uc544\ub294 \uac83\uacfc \uae38\uc744 \uac77\ub294 \uac83\uc740 \ub2e4\ub974\ub2e4.","Mengetahui jalan dan menjalani jalan adalah dua hal yang sama sekali berbeda."])
B.QX=new A.b8(["\u5263\u3088\u308a\u901f\u304f\u3001\u6c34\u3088\u308a\u67d4\u3089\u304b\u304f\u3001\u708e\u3088\u308a\u6fc0\u3057\u304f\u5728\u308c\u3002","Be faster than the sword, softer than water, fiercer than fire.","\uac80\ubcf4\ub2e4 \ube60\ub974\uace0, \ubb3c\ubcf4\ub2e4 \ubd80\ub4dc\ub7fd\uace0, \ubd88\ubcf4\ub2e4 \uaca9\ub82c\ud558\uac8c \uc788\uc5b4\ub77c.","Lebih cepat dari pedang, lebih lembut dari air, lebih ganas dari api."])
B.QH=new A.b8(["\u9375\u306f\u4eca\u3053\u306e\u77ac\u9593\u3060\u3002\u904e\u53bb\u3067\u3082\u672a\u6765\u3067\u3082\u306a\u3044\u3002","The key is now \u2014 not yesterday, not tomorrow, but this very moment.","\uc5f4\uc1e0\ub294 \ubc14\ub85c \uc9c0\uae08 \uc774 \uc21c\uac04\uc774\ub2e4. \uacfc\uac70\ub3c4 \ubbf8\ub798\ub3c4 \uc544\ub2cc.","Kuncinya adalah sekarang \u2014 bukan kemarin, bukan besok, tapi saat ini."])
B.R9=new A.b8(["\u5168\u529b\u3092\u51fa\u3057\u5207\u3063\u305f\u5f8c\u306b\u6b8b\u308b\u306e\u304c\u3001\u672c\u5f53\u306e\u81ea\u5206\u3060\u3002","What you are left with after you have given everything is who you truly are.","\uc804\ub825\uc744 \ub2e4\ud55c \ud6c4\uc5d0 \ub0a8\ub294 \uac83\uc774 \uc9c4\uc9dc \uc790\uc2e0\uc774\ub2e4.","Apa yang tersisa setelah kamu memberikan segalanya adalah siapa dirimu yang sebenarnya."])
B.QG=new A.b8(["\u3069\u308c\u3060\u3051\u77e5\u3063\u3066\u3044\u308b\u304b\u3067\u306f\u306a\u304f\u3001\u3069\u308c\u3060\u3051\u4f7f\u3048\u308b\u304b\u3060\u3002","It is not how much you know, but how much you can use.","\uc5bc\ub9c8\ub098 \uc544\ub290\ub0d0\uac00 \uc544\ub2c8\ub77c \uc5bc\ub9c8\ub098 \uc4f8 \uc218 \uc788\ub290\ub0d0\uc774\ub2e4.","Bukan seberapa banyak yang kamu tahu, tapi seberapa banyak yang bisa kamu gunakan."])
